mapper.select:
		select count(id) from wf_historic_task 


                instance_id = #{request.instanceId}


                task_def_id = #{request.taskDefinitionId}


                and start_time >= #{request.startTime}


                and end_time <= #{request.endTime}

		select id, process_def_id, instance_id, task_def_id, display_name, task_type, perform_type, state, operator, start_time,
		end_time, parent_task_id, variable 
		from wf_historic_task


                instance_id = #{request.instanceId}


                task_def_id = #{request.taskDefinitionId}


                and start_time >= #{request.startTime}


                and end_time <= #{request.endTime}



            order by #{request.sortString}
